const headers = $input.first().json.headers || {};
const secret = String(headers['x-nil-secret'] || headers['X-Nil-Secret'] || '').trim();
const expected = String($env.NIL_SECRET || $env.BASE_WEBHOOK_SECRET || '').trim();
if (!expected || secret !== expected) throw new Error('Unauthorized: invalid x-nil-secret');
const body = $input.first().json.body || $input.first().json;
const source = String(headers['x-event-source'] || body.event_source || body.source || 'unknown').toLowerCase();
const crypto = require('crypto');
const eventId = body.event_id || crypto.createHash('md5').update(JSON.stringify(body) + Date.now().toString()).digest('hex');
return [{ json: { ...body, _source: source, _event_id: eventId, _received_at: new Date().toISOString() } }];

const b = $json;
return [{ json: {
  event_type: 'click.event',
  source: 'wf_v9_06_cloudflare',
  idempotency_key: 'cf_event|' + b._event_id,
  payload: {
    event_id: b._event_id,
    tracking_code: b.pk || b.tracking_code || '',
    destination_type: b.destination || b.destination_type || 'unknown',
    occurred_at: b.occurred_at || b._received_at,
    country: b.country || '',
    device: b.device || ''
  }
} }];

const b = $json;
const payload = b.payload || b;
const eventType = String(b.event || '').toLowerCase();
const status = eventType.includes('cancel') ? 'cancelled' : eventType.includes('reschedule') ? 'rescheduled' : 'scheduled';
const invitee = payload.invitee || {};
return [{ json: {
  event_type: 'meeting.' + status,
  source: 'wf_v9_06_calendly',
  idempotency_key: 'calendly_meeting|' + (payload.event?.uuid || b._event_id),
  payload: {
    external_event_id: payload.event?.uuid || b._event_id,
    invitee_name: invitee.name || '',
    invitee_email: (invitee.email || '').toLowerCase(),
    event_name: payload.event_type?.name || 'Meeting',
    status,
    scheduled_start: payload.scheduled_event?.start_time || null,
    scheduled_end: payload.scheduled_event?.end_time || null,
    cancel_url: payload.cancel_url || '',
    reschedule_url: payload.reschedule_url || ''
  }
} }];

const b = $json;
const events = Array.isArray(b) ? b : [b];
return events.map(e => ({ json: {
  event_type: 'delivery.status',
  source: 'wf_v9_06_' + b._source,
  idempotency_key: 'delivery|' + (e.sg_message_id || e.MessageSid || e.message_id || b._event_id),
  payload: {
    provider_message_id: e.sg_message_id || e.MessageSid || '',
    status: e.event === 'delivered' ? 'delivered' : e.event === 'bounce' ? 'bounced' : e.event === 'failed' ? 'failed' : e.event || 'unknown',
    provider: b._source,
    error: e.reason || e.ErrorCode || ''
  }
} }));
